raw_code:
LadnerFischer[input_, ⊕_] := Module[
        {n = Length[input], levels = Log2[n], tree, sweep},

        (* Up-sweep phase *)
        tree = input;
        Do[
          ParallelDo[
            tree[[2^(l+1)*k + 2^l]] = 
              tree[[2^(l+1)*k]] ⊕ tree[[2^(l+1)*k + 2^l]],
            {k, 0, n/2^(l+1) - 1}
          ],
          {l, 0, levels - 1}
        ];

        (* Down-sweep phase *)
        tree[[n]] = Identity[⊕];
        Do[
          ParallelDo[
            Module[{left, right, temp},
              left = 2^(l+1)*k;
              right = left + 2^l;
              temp = tree[[left]];
              tree[[left]] = tree[[right]];
              tree[[right]] = temp ⊕ tree[[right]]
            ],
            {k, 0, n/2^(l+1) - 1}
          ],
          {l, levels - 1, 0, -1}
        ];

        tree
      ],

      (* Complexity *)
      WorkComplexity → O[n],
      SpanComplexity → O[Log n]
    },

    LadnerFischer
  ]
]
