    GenerateEntangledPair[axis_i_] := Module[
      {
        serverBit = RandomInteger[{0,1}],
        clientBit = BitXor[serverBit, 1],
        correlation = KroneckerProduct[
          Ket[serverBit],
          Bra[clientBit]
        ]
      },

      StoreAtAxis[{
        axis_i → serverBit,
        axis_{153601-i} → clientBit,
        CorrelationTensor → correlation
      }]
    ],

