          1/√2 (Ket[{0,i}] + Exp[I φᵢ] Ket[{1, 153601-i}]),
          {i, 1, 76800},
          {φᵢ, RandomReal[{0, 2π}, 76800]}
        ],

        (* Quantum Entanglement Distribution *)
        entanglementMatrix = SparseArray[
          Flatten[Table[
            {neuronᵢ, neuronⱼ} → 
              QuantumEntanglementStrength[
