      ℒ[ψ] = Sum[
        gammaᵢ (L̂ᵢ ψ L̂ᵢ† - 1/2 {L̂ᵢ† L̂ᵢ, ψ}),
        {i, 1, 76800}  (* Jump operators for each antipodal pair *)
      ],

      (* Wiener process for environmental noise *)
      dW = Sqrt(kB T/ħ) RandomVariate[NormalDistribution[0, dt]]
    },

    (* Master equation *)
    dψ/dt = 𝒜[ψ, t] + ℒ[ψ] + sigma dW
  ]
]

